#include <iostream>

using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    long long floors, doors_per_floor, door_number;
    cin >> floors >> doors_per_floor;
    cin >> door_number;

    // door_number is 1-indexed.
    // floor = (door_number - 1) / doors_per_floor + 1
    // position_on_floor = (door_number - 1) % doors_per_floor + 1

    long long floor = (door_number - 1) / doors_per_floor + 1;
    long long position = (door_number - 1) % doors_per_floor + 1;

    cout << floor << " " << position << "\n";

    return 0;
}
